-- R2: PROMOCION en sede 2
UPDATE products SET category = 'PERFUMERIA', brand = NULL, product_type = 'perfumes'
WHERE tenant_id = 'd46bec36-5259-4b5b-83c7-01f1e6ea5dcd'
  AND articulo = 'PROMOCION' AND sede_id = 'sede-pm-2';

-- R3: KITS-NIÑA y KITS-NIÑO en sede 2
UPDATE products SET category = 'PERFUMERIA', product_type = 'perfumes'
WHERE tenant_id = 'd46bec36-5259-4b5b-83c7-01f1e6ea5dcd'
  AND articulo IN ('KITS-NIÑA', 'KITS-NIÑO') AND sede_id = 'sede-pm-2';

-- R4: PURPURE-KITS en sede 2
UPDATE products SET category = 'PERFUMERIA', product_type = 'perfumes'
WHERE tenant_id = 'd46bec36-5259-4b5b-83c7-01f1e6ea5dcd'
  AND articulo LIKE 'PURPURE-KITS%' AND sede_id = 'sede-pm-2';

-- R5: REP- items con categoria CREMAS en sede 2 (verificacion/correccion)
UPDATE products SET category = 'PERFUMERIA', product_type = 'perfumes'
WHERE tenant_id = 'd46bec36-5259-4b5b-83c7-01f1e6ea5dcd'
  AND articulo IN (
    'REP-DOLCE Y GABBANA-K-MASC',
    'REP-LOUIS VUITTON CALIFORNIA- FEM',
    'REP-PACO RABANNE-INVICTUS LEGEND-MASC',
    'REP-PACO RABBANNE BLACK XS- FEM',
    'REP-PERRY ELLIS-360 CLASICA-MASC'
